const fs = require('fs');
const path = require('path');

// Scan both output dirs for slideshow folders
const dirs = ['/output', '/output/iteration3'];
const folders = [];

for (const dir of dirs) {
  try {
    const entries = fs.readdirSync(dir);
    for (const entry of entries) {
      const fullPath = path.join(dir, entry);
      const metaPath = path.join(fullPath, 'metadata.json');
      try {
        const stat = fs.statSync(fullPath);
        if (stat.isDirectory() && fs.existsSync(metaPath)) {
          const slides = fs.readdirSync(fullPath).filter(f => f.startsWith('slide_') && (f.endsWith('.jpg') || f.endsWith('.png')));
          if (slides.length > 0) {
            folders.push({ dir, name: entry, path: fullPath, slideCount: slides.length });
          }
        }
      } catch (e) { /* skip */ }
    }
  } catch (e) { /* dir doesn't exist */ }
}

// Load posted tracker
let posted = [];
const trackerPath = '/output/pinterest-posted.json';
try {
  posted = JSON.parse(fs.readFileSync(trackerPath, 'utf-8'));
} catch (e) { /* no tracker yet */ }

const postedNames = new Set(posted.map(p => p.folder));

// Find first unposted folder (newest first)
const unposted = folders
  .filter(f => !postedNames.has(f.name))
  .sort((a, b) => b.name.localeCompare(a.name));

if (unposted.length === 0) {
  return [{ json: { skip: true, reason: 'No unposted slideshow folders found' } }];
}

const selected = unposted[0];
const metadata = JSON.parse(fs.readFileSync(path.join(selected.path, 'metadata.json'), 'utf-8'));

// Select best slides (2-5): keep first (hook) and last (CTA), prefer JPG
let slideFiles = fs.readdirSync(selected.path)
  .filter(f => f.startsWith('slide_') && (f.endsWith('.jpg') || f.endsWith('.png')))
  .sort((a, b) => {
    const numA = parseInt(a.match(/slide_(\d+)/)?.[1] || '0');
    const numB = parseInt(b.match(/slide_(\d+)/)?.[1] || '0');
    return numA - numB;
  });

if (slideFiles.length > 5) {
  const first = slideFiles[0];
  const last = slideFiles[slideFiles.length - 1];
  const middle = slideFiles.slice(1, -1);
  const jpgs = middle.filter(f => f.endsWith('.jpg'));
  const pngs = middle.filter(f => f.endsWith('.png'));
  let picked = jpgs.length >= 3 ? jpgs.slice(0, 3) : [...jpgs, ...pngs.slice(0, 3 - jpgs.length)];
  picked.sort((a, b) => {
    const numA = parseInt(a.match(/slide_(\d+)/)?.[1] || '0');
    const numB = parseInt(b.match(/slide_(\d+)/)?.[1] || '0');
    return numA - numB;
  });
  slideFiles = [first, ...picked, last];
}

const slidePaths = slideFiles.map(f => path.join(selected.path, f));

return [{
  json: {
    skip: false,
    folder: selected.name,
    folderPath: selected.path,
    topic: metadata.topic || selected.name,
    hook: metadata.hook || '',
    caption: metadata.caption || '',
    hashtags: metadata.hashtags || [],
    slideFiles: slideFiles,
    slidePaths: slidePaths,
    slideCount: slideFiles.length
  }
}];

