const response = $input.first().json;
const content = response.choices[0].message.content;

let parsed;
try {
  const jsonMatch = content.match(/```(?:json)?\s*([\s\S]*?)```/);
  const jsonStr = jsonMatch ? jsonMatch[1].trim() : content.trim();
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Failed to parse Grok response: ' + e.message);
}

return [{ json: parsed }];

const fs = require('fs');

const grok = $('Parse Grok Response').first().json;
const content = $('Find Unposted Slideshow').first().json;

// Read slide images as binary data
const items = [];
for (let i = 0; i < content.slidePaths.length; i++) {
  const filePath = content.slidePaths[i];
  const fileName = content.slideFiles[i];
  const buffer = fs.readFileSync(filePath);
  const base64 = buffer.toString('base64');
  const mimeType = fileName.endsWith('.png') ? 'image/png' : 'image/jpeg';

  items.push({
    json: {
      title: grok.title,
      description: grok.description,
      board_name: grok.board_name,
      folder: content.folder,
      slideIndex: i,
      fileName: fileName
    },
    binary: {
      data: {
        data: base64,
        mimeType: mimeType,
        fileName: fileName
      }
    }
  });
}

// Return just the first item with all images for Pinterest
// Pinterest Create Pin takes a single image per pin
// We'll create one pin with the hook slide as the main image
return [items[0]];

const fs = require('fs');

const content = $('Find Unposted Slideshow').first().json;
const pinResult = $input.first().json;

// Update tracker
const trackerPath = '/output/pinterest-posted.json';
let posted = [];
try {
  posted = JSON.parse(fs.readFileSync(trackerPath, 'utf-8'));
} catch (e) { /* new tracker */ }

posted.push({
  folder: content.folder,
  pinId: pinResult.id || 'unknown',
  postedAt: new Date().toISOString(),
  topic: content.topic
});

fs.writeFileSync(trackerPath, JSON.stringify(posted, null, 2));

return [{
  json: {
    success: true,
    folder: content.folder,
    topic: content.topic,
    pinId: pinResult.id
  }
}];
